// Miller-Rabin primality test (ES2025 probabilistic)
// 99.9999% accurate for numbers < 2^64
function isPrimeMillerRabin(n) {
  if (n <= 1) return false;
  if (n <= 3) return true;
  if (n % 2 === 0) return false;

  // Write n-1 as 2^s * d
  let s = 0, d = n - 1;
  while (d % 2 === 0) {
    d /= 2;
    s++;
  }

  // Witnesses for deterministic < 2^64
  const witnesses = [
    2, 3, 5, 7, 11, 13, 17, 23, 29, 31, 37
  ];

  for (const a of witnesses) {
    if (a >= n) break;
    let x = modPow(a, d, n); // a^d mod n
    if (x === 1 || x === n - 1) continue;

    let r = 1;
    while (r < s && x !== n - 1) {
      x = (x * x) % n;
      r++;
      if (x === 1) return false;
    }
    if (x !== n - 1) return false;
  }
  return true;
}

// Modular exponentiation (fast pow)
function modPow(base, exp, mod) {
  let result = 1;
  base %= mod;
  while (exp > 0) {
    if (exp % 2 === 1) result = (result * BigInt(base)) % BigInt(mod);
    exp = Math.floor(exp / 2);
    base = (BigInt(base) * BigInt(base)) % BigInt(mod);
  }
  return Number(result);
}

// Usage
console.log(isPrimeMillerRabin(2147483647)); // true (2^31-1)
